6,0.02514146,-0.02263178,0.06151827,-0.02852399,0.03643291,0.04968933,0.00338205,0.02641226,-0.02675179,0.09676479,-0.01348885,0.03854693,-0.08500043,0.02708066,0.02003787,0.00827835,-0.05669689,-0.04036100,0.00244173,-0.00160017,-0.01729383,0.01824421,-0.08465599,-0.04772750,-0.01583293,-0.04865821,-0.00037080,-0.03151045,-0.07874928,-0.05317541,-0.01421952,0.01902137,-0.04045773,-0.00472054,0.00845617,-0.08023331,0.03921013,-0.04079608,0.02101705,0.06406527,0.01469068,0.01300407]',E'Route Prefixing\n\nTo use a prefix for all routes, place them inside a plugin:\n\n```js\nconst fastify = require(''fastify'')()\n\nconst route = {\n    method: ''POST'',\n    url: ''/login'',\n    handler: () => {},\n    schema: {},\n}\n\nfastify.register(function (app, _, done) {\n  app.get(''/users'', () => {})\n  app.route(route)\n\n  done()\n}, { prefix: ''/v1'' }) // global route prefix\n\nawait fastify.listen({ port: 3000 })\n```','{"source": "fastify", "version": "5", "language": "javascript", "title": "Routes", "section_title": "Routes", "url": "https://github.com/fastify/fastify/blob/main/docs/Reference/Routes.md", "topics": "fastify,node,http,Routes", "categories": "web,javascript,rest"}');
