9,0.20620117,0.05377250,-0.04274624,0.08864941,0.07669029,-0.01082640,0.09286608,0.01386275,0.01995719,0.02856043,0.07352103,-0.03598278,-0.01734268,0.02902007,-0.02061257,0.01470922,-0.01640252,-0.05117299,0.00608220,0.00953417,0.03810446,-0.00239679,0.05276814,-0.05117494,-0.05454717,-0.07982499,-0.05320069,0.00108744,-0.03712213,-0.08342024,0.00356303,-0.05067421,0.00699322,0.02746471,0.04468832,0.05835693,-0.04005285,0.00858016,0.00961868,0.04813572,0.08056226,0.08703530,0.00802225]',E'Validator Compiler\n\n**Use try-catch for safety:**\n```js\nfastify.setValidatorCompiler(({ schema }) => {\n  return (data) => {\n    try {\n      // Validation logic here\n      const result = schema.validate(data)\n      if (result.error) {\n        return { error: result.error }\n      }\n      return { value: result.value }\n    } catch (e) {\n      // Catch any unexpected errors\n      return { error: e }\n    }\n  }\n})\n```','{"source": "fastify", "version": "5", "language": "javascript", "title": "Validation And Serialization", "section_title": "Validation-and-Serialization", "url": "https://github.com/fastify/fastify/blob/main/docs/Reference/Validation-and-Serialization.md", "topics": "fastify,node,http,Validation,and,Serialization", "categories": "web,javascript,rest"}');
